diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 756b25ac9856..04b6d28802d1 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -20983,28 +20983,48 @@ bool SLPVectorizerPass::vectorizeGEPIndices(BasicBlock *BB, BoUpSLP &R) {
       if (Candidates.size() < 2)
         continue;

-      // Add the single, non-constant index of each candidate to the bundle. We
-      // ensured the indices met these constraints when we originally collected
-      // the getelementptrs.
-      SmallVector<Value *, 16> Bundle(Candidates.size());
-      auto BundleIndex = 0u;
+      // Group candidates by the basic block of their single, non-constant
+      // index producer to avoid forming bundles with instructions from
+      // different basic blocks, which violates placement constraints.
+      DenseMap<BasicBlock *, SmallVector<GetElementPtrInst *, 16>> ByBB;
+      SmallVector<GetElementPtrInst *, 16> NonInstIdx;
       for (auto *V : Candidates) {
         auto *GEP = cast<GetElementPtrInst>(V);
         auto *GEPIdx = GEP->idx_begin()->get();
         assert(GEP->getNumIndices() == 1 && !isa<Constant>(GEPIdx));
-        Bundle[BundleIndex++] = GEPIdx;
+        if (auto *I = dyn_cast<Instruction>(GEPIdx)) {
+          ByBB[I->getParent()].push_back(GEP);
+        } else {
+          // Non-instruction indices (e.g., arguments) can be used with any BB,
+          // collect them separately and append to each BB group later.
+          NonInstIdx.push_back(GEP);
+        }
       }

-      // Try and vectorize the indices. We are currently only interested in
-      // gather-like cases of the form:
-      //
-      // ... = g[a[0] - b[0]] + g[a[1] - b[1]] + ...
-      //
-      // where the loads of "a", the loads of "b", and the subtractions can be
-      // performed in parallel. It's likely that detecting this pattern in a
-      // bottom-up phase will be simpler and less costly than building a
-      // full-blown top-down phase beginning at the consecutive loads.
-      Changed |= tryToVectorizeList(Bundle, R);
+      // For each BB-specific group (with size >= 2), build a bundle from its
+      // indices and try to vectorize. Append non-instruction indices if present
+      // to allow forming larger bundles within the same BB.
+      for (auto &P : ByBB) {
+        auto &Group = P.second;
+        if (Group.size() < 2)
+          continue;
+        SmallVector<Value *, 16> Bundle;
+        Bundle.reserve(Group.size() + NonInstIdx.size());
+        for (auto *GEP : Group)
+          Bundle.push_back(GEP->idx_begin()->get());
+        for (auto *GEP : NonInstIdx)
+          Bundle.push_back(GEP->idx_begin()->get());
+        // Try and vectorize the indices. We are currently only interested in
+        // gather-like cases of the form:
+        //
+        // ... = g[a[0] - b[0]] + g[a[1] - b[1]] + ...
+        //
+        // where the loads of "a", the loads of "b", and the subtractions can be
+        // performed in parallel. It's likely that detecting this pattern in a
+        // bottom-up phase will be simpler and less costly than building a
+        // full-blown top-down phase beginning at the consecutive loads.
+        Changed |= tryToVectorizeList(Bundle, R);
+      }
     }
   }
   return Changed;

